class Solution:
    def nthSuperUglyNumber(self, n, primes):
        k = len(primes)
        ugly = [1] * n
        idx = [0] * k
        cand = list(primes)
        for i in range(1, n):
            m = min(cand)
            ugly[i] = m
            for j in range(k):
                if cand[j] == m:
                    idx[j] += 1
                    cand[j] = primes[j] * ugly[idx[j]]
        return ugly[n - 1]

