var nthSuperUglyNumber = function(n, primes) {
    const k = primes.length;
    const ugly = new Array(n).fill(1);
    const idx = new Array(k).fill(0);
    const cand = primes.slice();
    for (let i = 1; i < n; i++) {
        let m = cand[0];
        for (let j = 1; j < k; j++) if (cand[j] < m) m = cand[j];
        ugly[i] = m;
        for (let j = 0; j < k; j++) {
            if (cand[j] === m) {
                idx[j]++;
                cand[j] = primes[j] * ugly[idx[j]];
            }
        }
    }
    return ugly[n - 1];
};
